import './kpi-card.js';import './revenue-chart.js';import './activity-feed.js';import './project-progress.js';import './alerts-widget.js';import './pie-chart-widget.js';import './line-chart-widget.js';import './area-chart-widget.js';import './bar-chart-widget.js';import './realtime-stats-widget.js';import './performance-gauge-widget.js';import './data-table-widget.js';export function initializeWidgets(){window.dispatchEvent(new CustomEvent('dashboard-widgets-ready'));}export function updateWidgetData(widgetId,data){const widget=document.getElementById(widgetId);if(!widget){return;}Object.entries(data).forEach(([key,value])=>{if(widget.hasAttribute(key)){widget.setAttribute(key,value);}});}export function refreshAllWidgets(){const events=[ new CustomEvent('kpi-refresh'),new CustomEvent('revenue-refresh'),new CustomEvent('activity-refresh'),new CustomEvent('project-refresh'),new CustomEvent('alerts-refresh'),new CustomEvent('pie-chart-refresh'),new CustomEvent('line-chart-refresh'),new CustomEvent('area-chart-refresh'),new CustomEvent('bar-chart-refresh')];events.forEach(event=>window.dispatchEvent(event));}export function registerWidgets(){}if(typeof window!=='undefined'){window.addEventListener('DOMContentLoaded',()=>{initializeWidgets();});}